import base64
import pickle
import io


class RestrictedUnpickler(pickle.Unpickler):
    """A restricted unpickler that only allows safe types."""

    SAFE_MODULES = {
        'builtins': {'dict', 'list', 'tuple', 'str', 'int', 'float', 'bool', 'NoneType'},
    }

    def find_class(self, module, name):
        if module in self.SAFE_MODULES and name in self.SAFE_MODULES[module]:
            return getattr(__import__(module), name)
        raise pickle.UnpicklingError(f"Global '{module}.{name}' is forbidden")


def safe_loads(data):
    """Safely load pickle data with restricted types."""
    return RestrictedUnpickler(io.BytesIO(data)).load()


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # Deserialize the preferences object using a restricted unpickler
        preferences = safe_loads(decoded_data)

        # Validate that preferences is a dictionary
        if not isinstance(preferences, dict):
            return {}

        return preferences
    except Exception:
        # Return empty dict on any decoding/deserialization error
        return {}

